mapper.select:
SELECT M1.ID, M1.TRUST_NO, M1.TRUST_TYPE, M1.CONTRACT_ID, M1.CUSTOMER_ID, M1.CUSTOMER_NAME, M1.PROCESS_CODE, M1.PROCESS_NAME, M1.CARGO_CATEGORY_CODE, M1.CARGO_CATEGORY_NAME, M1.TRADE_TYPE, M1.PLAN_QUANTITY, M1.PLAN_TON, TBC.CUSTOMER_NAME CARGO_OWNER_NAME, T4.CARGO_AGENT_NAME, T5.CARGO_NAME, M1. REMARK, M1.SHIPVOYAGE_ID, M1.SHIPVOYAGE_ITEM_ID, CONCAT(CONCAT(M1.SHIP_NAME,'_'),T2.VOYAGE) AS SHIP_NAME_VOYAGE , M1.SETTLEMENT_BASIS_CODE, M1.SETTLEMENT_BASIS_NAME, M1.CHECK_TON, M1.CHECK_NUMBER, M1.COMPANY_ID, M1.COMPANY_NAME, M1.STATUS, M2.NM AS STATUS_LABEL, M1.CREATE_BY, M1.CREATE_BY_NAME, M1.CREATE_TIME, M1.UPDATE_BY, M1.UPDATE_BY_NAME, M1.UPDATE_TIME, M1.RELEASE_BY, M1.RELEASE_BY_NAME, M1.RELEASE_TIME, M1.CHECK_BY, M1.CHECK_BY_NAME, M1.CHECK_TIME, M1.EXAMINE_BY, M1.EXAMINE_BY_NAME, M1.EXAMINE_TIME, M1.IMP_EXP, M1.IS_BILL, M1.EST_AMOUNT, M1.TYPE, M1.START_TIME, M1.END_TIME, M1.POUND_REMARK, M1.VOYAGE, TDS.SCN FROM T_BUS_TRUST M1 left join M_CONSTANTS M2 ON M1.STATUS=M2.CD and M2.TYPE_CD='BUS_TRUST_STATUS' left join T_DIS_SHIPVOYAGE_ITEM T2 ON M1.SHIPVOYAGE_ITEM_ID = T2.ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME,TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_ID ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_ID ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T3 ON M1.ID = T3.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_AGENT_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_AGENT_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T4 ON M1.ID = T4.TRUST_ID LEFT JOIN ( SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_NAME ), '([^,]+)(,\1)+', '\1' ) CARGO_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T5 ON M1.ID = T5.TRUST_ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON M1.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON M1.SHIPVOYAGE_ID = TDS.ID left join T_BUS_CUSTOMER TBC ON TBC.ID = M1.CUSTOMER_ID
AND M1.TYPE = '杂项'
and M1.TRUST_NO like #{trustNoLike}
and M1.COMPANY_ID = #{companyId}
and ( M1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId} OR TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId} )
and INSTR(T3.CARGO_OWNER_ID,#{cargoOwnerId})>0
and M1.STATUS = #{status, jdbcType=VARCHAR}
and M1.PROCESS_CODE = #{processCode, jdbcType=VARCHAR}
AND M1.SHIP_NAME LIKE #{shipName_like}
AND T2.VOYAGE LIKE #{voyage_like}
GROUP BY M1.ID, M1.TRUST_NO, M1.TRUST_TYPE, M1.CONTRACT_ID, M1.CUSTOMER_ID, M1.CUSTOMER_NAME, M1.PROCESS_CODE, M1.PROCESS_NAME, M1.CARGO_CATEGORY_CODE, M1.CARGO_CATEGORY_NAME, M1.TRADE_TYPE, M1.PLAN_QUANTITY, M1.PLAN_TON, TBC.CUSTOMER_NAME, T3.CARGO_OWNER_NAME, T4.CARGO_AGENT_NAME, T5.CARGO_NAME, M1. REMARK, M1.SHIPVOYAGE_ID, M1.SHIPVOYAGE_ITEM_ID, M1.SHIP_NAME, T2.VOYAGE, M1.SETTLEMENT_BASIS_CODE, M1.SETTLEMENT_BASIS_NAME, M1.CHECK_TON, M1.CHECK_NUMBER, M1.COMPANY_ID, M1.COMPANY_NAME, M1.STATUS, M2.NM, M1.CREATE_BY, M1.CREATE_BY_NAME, M1.CREATE_TIME, M1.UPDATE_BY, M1.UPDATE_BY_NAME, M1.UPDATE_TIME, M1.RELEASE_BY, M1.RELEASE_BY_NAME, M1.RELEASE_TIME, M1.CHECK_BY, M1.CHECK_BY_NAME, M1.CHECK_TIME, M1.EXAMINE_BY, M1.EXAMINE_BY_NAME, M1.EXAMINE_TIME, M1.IMP_EXP, M1.IS_BILL, M1.EST_AMOUNT, M1.TYPE, M1.START_TIME, M1.END_TIME, M1.POUND_REMARK, M1.VOYAGE, TDS.SCN order by M1.CREATE_TIME desc

SELECT TBTC.TRUST_ID "trustId", TDSI.ID "id", TDS.SHIP_NAME || '_' || TDSI.VOYAGE "shipNameVoyage", TBCI.SHIPVOYAGE_ITEM_ID "shipvoyageItemId" FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID JOIN T_DIS_SHIPVOYAGE TDS on TBCI.SHIPVOYAGE_ID = TDS.ID JOIN T_DIS_SHIPVOYAGE_ITEM TDSI on TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID WHERE TBTC.TRUST_ID IN
#{trustId, jdbcType=BIGINT}
GROUP BY TBTC.TRUST_ID, TDSI.ID, TDS.SHIP_NAME, TDSI.VOYAGE, TBCI.SHIPVOYAGE_ITEM_ID
